In the [Kerberos (GSSAPI/SSPI)|http://mongodb.github.io/node-mongodb-native/2.2/tutorials/connect/authenticating/] section, the server and principal domains are currently:
{code}
// KDC Server
var server = "kerberos.example.com";
var principal = "drivers@KERBEROS.EXAMPLE.COM";
{code}

It could be confusing for the KDC domain and MongoDB server to be the same. Perhaps this is better:
{code}
var server = "mongo-server.example.com";
var principal = "drivers@KERBEROS.EXAMPLE.COM";
{code}

This change originates from a community user who made a similar suggestion for the Python and Casbah docs. See FREE-137466.

Add next test code to Node.js mongodb driver test suite.

{noformat}
exports['Should correctly find one document with custom fields and undefined callback'] = {
  metadata: {
    requires: {
      promises: true,
      topology: ['single']
    }
  },
  test: function (configuration, test) {
    var db = configuration.newDbInstance(configuration.writeConcernMax(), {
      poolSize: 1,
      auto_reconnect: false
    });

    db.open().then(function (db) {
      var collection = db.collection('findOneDocumentCustomFieldsUndefinedCallback');
      collection.insertMany([{
        a: 1,
        b: 1
      }, {
        a: 2,
        b: 2
      }, {
        a: 3,
        b: 3
      }, {
        a: 4,
        b: 4
      }], configuration.writeConcernMax()).then(function (result) {

        // Show that duplicate records got dropped
        collection.findOne({
          a: 1
        }, {
          fields: {
            b: 1,
            _id: 0
          }
        }, undefined).then(function (item) {
          test.equal(item._id, undefined);
          test.equal(item.b, 1);
          test.equal(item.a, undefined);
          db.close();
          test.done();
        });
      });
    });
  }
}
{noformat}

I expect {{findOne}} works in the same way with two arguments and three arguments with {{undefined}} or {{null}} as value.

Assume this code:
{code}
var MongoClient = require('mongodb').MongoClient;
MongoClient.connect('mongodb://SERVER:27017/test?readPreference=secondaryPreferred', function(err, db) {
	db.listCollections().toArray().then(collections => console.log(collections)).then(() => db.close());
});
{code}

This should list all collections in the 'test' db, regardless of whether 'SERVER' is currently a primary or not.

This does not work: if SERVER is a secondary, then this will log something like:
{code}
(node:16946) UnhandledPromiseRejectionWarning: Unhandled promise rejection (rejection id: 1): MongoError: not master and slaveOk=false
{code}

I think the problem can be fixed with the attached patch.

I have a database with a collection 'institutions'. It has a field with an array of tuples: 'institutions.person_id_role_id'. Each tuple is a pair of ObjectIds pointing to the collection 'person' and 'role', respectively.

The following expression works well:
db.getCollection('institutions').find({ "person_id_role_id" : { "$elemMatch" : { "0" : {$eq:ObjectId("59bec3d719f9d536a018438e")}}}});

After I index parts of the array of pairs:
db.getCollection('institutions').ensureIndex({"person_id_role_id.0":1});
db.getCollection('institutions').ensureIndex({"person_id_role_id.1":1});

... the upper expression does not work anymore. If I delete the index, it works again.

I feel as if something is wrong here. Perhaps the indexing does not resolve ".0" correctly (sometimes meaning first array pair, and sometimes meaning left part of the pair in the array).

Please help! How would you solve this?

The issue occurs only when using the "mongos" topology. Removing the offending event listener on connection close seems to solve the issue:

{code:javascript}
db.s.topology.s.mongos.on('joined', (_, server) => {
	server.once('close', () => {
		server.removeAllListeners('serverDescriptionChanged');
	});
});
{code}

Unlike the doc [stated|http://mongodb.github.io/node-mongodb-native/3.0/api/FindOperatorsUnordered.html#updateOne], the following code returns FindOperatorsUnordered instead of UnorderedBulkOp


{code:javascript}
const { MongoClient } = require('mongodb');

const url = 'mongodb://localhost:27017';

const dbName = 'dbname';

MongoClient.connect(url, (err, client) => {
  console.log('Connected successfully to server');

  const db = client.db(dbName);

  const batch = db.collection('Products').initializeUnorderedBulkOp();

  console.log(batch.find({ code: 1 }).updateOne({ change: true }));
  console.log(batch);
});
{code}

The guide to install MongoDB Node.js driver on earlier versions need to specify version number: 

http://mongodb.github.io/node-mongodb-native/2.2/installation-guide/installation-guide/#mongodb-driver

{code}
npm install mongodb --save
{code}

Should be something as below: 

{code}
npm install mongodb@2.2 --save
{code}

Without version number specified, the command will download the latest package version v3.+ which is not backward compatible to v2. 
i.e. if someone would follow the installation/tutorial guide they would encounter issues

The aggregation example code on 
http://mongodb.github.io/node-mongodb-native/3.0/tutorials/aggregation/#the-aggregation-pipeline
Should show how to process the cursor returned instead of printing cursor object. 

{code}
const collection = db.collection( 'restaurants' );
  collection.aggregate(
      [ { '$match': { "borough": "Bronx" } },
        { '$unwind': '$categories'},
        { '$group': { '_id': "$categories", 'Bronx restaurants': { '$sum': 1 } } }
      ],
	  function(err, results) {
        assert.equal(err, null);
        console.log(results)
        callback(results);
      }
  );
{code}

For example, this should have shown: 

{code}
const collection = db.collection( 'restaurants' );
  collection.aggregate(
      [ { '$match': { "borough": "Bronx" } },
        { '$unwind': '$categories'},
        { '$group': { '_id': "$categories", 'Bronx restaurants': { '$sum': 1 } } }
      ],
	  function(err, cursor) {
        assert.equal(err, null);

        cursor.toArray(function(err, document){
            console.log(document);
        });
        callback(results);
      }
  );
{code}

